import{_ as e,W as t,X as l,Z as n,$ as i,a0 as a}from"./framework-805da640.js";const g={},p=n(`<h2 id="冯-•-诺依曼结构" tabindex="-1"><a class="header-anchor" href="#冯-•-诺依曼结构" aria-hidden="true">#</a> 冯 • 诺依曼结构</h2><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230601221654.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="运算器" tabindex="-1"><a class="header-anchor" href="#运算器" aria-hidden="true">#</a> 运算器</h3><p>功能：执行算术逻辑运算 组成：</p><ul><li>ALU: 用于执行各种算术和逻辑运算，包括加、减、乘、除、与、或、非、移位等。</li><li>数据寄存器： 用于存储运算器中的操作数和运算结果。</li><li>状态寄存器：用于存储运算器的运算状态，例如运算结果是否为零、是否溢出等。</li></ul><h3 id="控制器" tabindex="-1"><a class="header-anchor" href="#控制器" aria-hidden="true">#</a> 控制器</h3><p>功能：从内存中加载程序指令并提供给运算器所需的操作数和操作码，驱动程序指令的执行。 组成：</p><ul><li>指令寄存器(IR): 存储从存储器加载的当前正在执行的指令</li><li>程序计数器(PC): 保存下一条要执行的指令的存储器地址</li><li>指令译码器: 用于将指令解码成控制信号，以便控制器可以控制其他组件执行指令</li><li>时序逻辑：用于根据指令译码器解码出的指令信息，生成控制信号，控制其他组件执行指令</li><li>中断控制器：用于处理计算机中的中断请求，以便及时响应外部设备的请求并完成相应的处理任务</li></ul><h3 id="存储器" tabindex="-1"><a class="header-anchor" href="#存储器" aria-hidden="true">#</a> 存储器</h3><p>功能：用于存储程序和数据，程序和数据都以二进制形式存储，并且存储器中的地址是连续的。程序和数据都可以通过地址来访问和操作。 组成：</p><ul><li>主存储器（Main Memory）</li></ul><p>通常是指随机存储器（Random Access Memory，RAM），它具有随机访问的特性，可以在短时间内存取或写入任意存储单元中的数据。</p><ul><li>辅助存储器（Secondary Storage）</li></ul><p>通常是指硬盘、光盘、U盘等外部存储设备，它们通常具有较大的存储容量和较慢的读写速度，但可以永久保存数据和程序。</p><h3 id="输入设备" tabindex="-1"><a class="header-anchor" href="#输入设备" aria-hidden="true">#</a> 输入设备</h3><p>功能：允许用户或程序从外部输入数据，常见的输入设备有键盘、鼠标、摄像头、麦克风等</p><h3 id="输出设备" tabindex="-1"><a class="header-anchor" href="#输出设备" aria-hidden="true">#</a> 输出设备</h3><p>功能：允许将程序的输出结果展示到外部设备中，常见的输出设备有显示器、扬声器等</p><p>其中，运算器和控制器合称为CPU。</p><h2 id="工作流程" tabindex="-1"><a class="header-anchor" href="#工作流程" aria-hidden="true">#</a> 工作流程</h2><ol><li>取指令</li></ol><p>控制器的PC寄存器存放了下一条指令的地址，将该地址放到地址总线上，控制总线上发出<code>read</code>信号，内存将该地址的数据放到数据总线上，结果保存到IR寄存器中，PC寄存器自动增加以指向下一条指令</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603094903.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol><li>分析指令</li></ol><p>根据指令集的定义区分操作码和操作数，并去指定位置(立即数、寄存器、内存)取操作数，输入到运算器中</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603095222.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="3"><li>执行指令</li></ol><p>运算器执行相应的运算</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603095522.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="4"><li>存储结果</li></ol><p>将运算结果保存到指定位置，如这里是保存到内存中</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603095542.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="电路实现" tabindex="-1"><a class="header-anchor" href="#电路实现" aria-hidden="true">#</a> 电路实现</h2><p>思路：先设计简单的1个bit的电路，可以列真值表设计出逻辑电路结构，(可以的话将其优化一下)，然后将其当作黑箱封装，作为基本块一步步设计更复杂的电路</p><h3 id="运算电路" tabindex="-1"><a class="header-anchor" href="#运算电路" aria-hidden="true">#</a> 运算电路</h3><p>以加法器为例：</p><p>真值表：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603100128.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>SUM: <span class="token punctuation">(</span>NOT<span class="token punctuation">(</span>A<span class="token punctuation">)</span> AND B<span class="token punctuation">)</span> OR <span class="token punctuation">(</span>A AND NOT<span class="token punctuation">(</span>B<span class="token punctuation">))</span> <span class="token comment"># 1 when exactly one of A or B is 1</span>
CARRY OUT: A AND B <span class="token comment"># 1 when both A and B are 1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>一位加法器：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603100048.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>四位加法器：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603100613.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="控制电路" tabindex="-1"><a class="header-anchor" href="#控制电路" aria-hidden="true">#</a> 控制电路</h3><ul><li><strong>复用器</strong>：从多个输入中选择一个作为输出</li></ul><p>1bit的2路复用器：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603100957.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>1bit的4路复用器：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603101101.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li><strong>分用器</strong>：从多个输出中选择一个来接收输入</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603101419.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>`,51),o=i("ul",null,[i("li",null,[i("strong",null,"解码器"),a("：输入N-bit的值，将结果传输到"),i("span",{class:"katex"},[i("span",{class:"katex-mathml"},[i("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[i("semantics",null,[i("mrow",null,[i("msup",null,[i("mn",null,"2"),i("mi",null,"N")])]),i("annotation",{encoding:"application/x-tex"},"2^N")])])]),i("span",{class:"katex-html","aria-hidden":"true"},[i("span",{class:"base"},[i("span",{class:"strut",style:{height:"0.8413em"}}),i("span",{class:"mord"},[i("span",{class:"mord"},"2"),i("span",{class:"msupsub"},[i("span",{class:"vlist-t"},[i("span",{class:"vlist-r"},[i("span",{class:"vlist",style:{height:"0.8413em"}},[i("span",{style:{top:"-3.063em","margin-right":"0.05em"}},[i("span",{class:"pstrut",style:{height:"2.7em"}}),i("span",{class:"sizing reset-size6 size3 mtight"},[i("span",{class:"mord mathnormal mtight",style:{"margin-right":"0.10903em"}},"N")])])])])])])])])])]),a("个输出之一")])],-1),s=n('<figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603101258.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="存储电路" tabindex="-1"><a class="header-anchor" href="#存储电路" aria-hidden="true">#</a> 存储电路</h3><ul><li><strong>锁存器</strong></li></ul><p>RS锁存器：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603101722.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>门控D锁存器：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603101802.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>寄存器可由多个门控D锁存器实现。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603101838.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="设计" tabindex="-1"><a class="header-anchor" href="#设计" aria-hidden="true">#</a> 设计</h2><p>Register File:</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603102750.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>CPU:</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603102707.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>时钟信号：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603103012.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>时钟边缘触发电路状态变化，驱动指令执行。</p><ul><li>上升沿：输入稳定，可以进行下一步操作</li><li>下降沿：输出稳定，可以读取结果</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/blog/Snipaste_2023-06-03_10-33-05.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>时钟周期的长度要保证电路传播耗时最长的阶段能够完成，一般是执行指令阶段。</p><h2 id="优化" tabindex="-1"><a class="header-anchor" href="#优化" aria-hidden="true">#</a> 优化</h2><h3 id="流水线" tabindex="-1"><a class="header-anchor" href="#流水线" aria-hidden="true">#</a> 流水线</h3><ul><li>没有流水线：</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603103721.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>每条指令需要的时钟周期数CPI = 4</p><ul><li>使用流水线：</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603103856.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>每条指令需要的时钟周期数CPI = 1</p><p><strong>流水线的不足</strong>：</p><ul><li><p>数据方面：</p><ul><li>指令需要的时钟周期数不一致</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603104117.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li>结果不一致</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230603104157.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure></li><li><p>控制方面</p></li></ul><p>分支跳转</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/Snipaste_2023-06-03_10-42-36.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>',32),r=[p,o,s];function d(c,h){return t(),l("div",null,r)}const f=e(g,[["render",d],["__file","CPU原理.html.vue"]]);export{f as default};
